template<const int N>
class Matrix {
public:
	// 下标从 1 开始
	array<array<ll, N + 1>, N + 1> mat;

	Matrix() {
		for (int i = 0; i <= N; i++)
			for (int j = 0; j <= N; j++)
				mat[i][j] = 0;
	}

	void ksm(ll k, Matrix& base) {
		while (k) {
			if (k & 1)*this = *this * base;
			base = base * base;
			k >>= 1;
		}
	}

	Matrix operator* (const Matrix& x) {
		// 矩阵乘法
		Matrix ret;
		for (int i = 1; i <= N; i++)
			for (int k = 1; k <= N; k++) {
				if (mat[i][k] == 0) continue; // 简单剪枝
				for (int j = 1; j <= N; j++) {
					ret.mat[i][j] = (ret.mat[i][j] + mat[i][k] * x.mat[k][j] % mod) % mod;
				}
			}
		return ret;
	}

	void init_ans() {
		// 答案矩阵大小 1 · 2mx
		// V = { dp[i][0], dp[i][1], dp[i - 1][0], dp[i - 1][1],..., dp[i - mx + 1][0], dp[i - mx + 1][1] }
		// 游戏开始，轮到 L，等价于 dp[0][1] = 1，即 F 刚操作完到 0
		mat[1][2] = 1;
	}

	void init_base(ll m1, ll m2, ll n1, ll n2, ll p, ll q) {
		// 系数矩阵大小 mx · mx

		// dp[i][0] = p * dp[i - m1][1] + (1 - p) * dp[i - m2][1]
		mat[2 * m1][1] = (mat[2 * m1][1] + p) % mod;
		mat[2 * m2][1] = (mat[2 * m2][1] + ((1 - p) % mod + mod) % mod) % mod;

		// dp[i][1] = q * dp[i - n1][0] + (1 - q) * dp[i - n2][0]
		mat[2 * n1 - 1][2] = (mat[2 * n1 - 1][2] + q) % mod;
		mat[2 * n2 - 1][2] = (mat[2 * n2 - 1][2] + ((1 - q) % mod + mod) % mod) % mod;

		// i 继承 i - 1 的 dp 值用
		fa(i, 3, N) {
			mat[i - 2][i] = 1;
		}
	}
};

Matrix<105> ans, base;
void solve(int CASE)
{
	ll m1, m2, n1, n2, z; cin >> m1 >> m2 >> n1 >> n2 >> z;
	ll p, q; cin >> p >> q;

	// dp[pos][0]：当前 L 已经操作完，且总数达到 pos 的概率
	// dp[pos][1]：当前 F 已经操作完，且总数达到 pos 的概率
	base.init_base(m1, m2, n1, n2, p, q);
	ans.init_ans();
	if (z > 1)ans.ksm(z - 1, base); // 从 dp[0] 更新到 dp[z - 1]

	ll res = 0;
	ll mx = max({ m1, m2, n1, n2 });

	fa(k, 0, mx) {
		// 枚举 L 最后一步起跳的位置 pos
		ll pos = (z - 1) - k; 
		if (pos < 0)break;

		// 在答案行向量 V_{z-1} 中寻找 dp[pos][1]
		// dp[z - 1][1] -> Mat[2]
		// dp[z - 2][1] -> Mat[4]
		// ...
		// dp[z - 1 - k][1] -> Mat[(k + 1) * 2]
		if (2 * k + 2 > 105)break;

		ll prob_F_fin = ans.mat[1][2 * k + 2]; // F 在 pos 处结束的概率
		if (!prob_F_fin)continue;

		if (pos + m1 >= z) // L 操作 m1
			res = (res + prob_F_fin * p) % mod;
		if (pos + m2 >= z) // L 操作 m2
			res = (res + prob_F_fin * ((1 - p + mod) % mod)) % mod;
	}
	cout << res << endl;
	return;
}
